// ImageDimensions image dimensions in pixels.
//
// Binding-safe replacement for `(u32, u32)` tuples, which degrade to
// `Vec<Vec<String>>` when sanitized for cross-language binding generation.
// Used by both `ImageMetadata` and
// `InlineImage`.
type ImageDimensions struct {
	Width  uint32 `json:"width"`
	Height uint32 `json:"height"`
}

// DocumentStructure structured document tree representing the semantic content of an HTML document.
//
// Uses a flat node array with index-based parent/child references for efficient traversal.
type DocumentStructure struct {
	Nodes        []DocumentNode `json:"nodes,omitempty"`
	SourceFormat *string        `json:"source_format,omitempty"`
}

// DocumentNode single node in the document tree.
type DocumentNode struct {
	ID          string            `json:"id"`
	Content     NodeContent       `json:"content"`
	Parent      *uint32           `json:"parent,omitempty"`
	Children    []uint32          `json:"children,omitempty"`
	Annotations []TextAnnotation  `json:"annotations,omitempty"`
	Attributes  map[string]string `json:"attributes,omitempty"`
}

func (s *DocumentNode) UnmarshalJSON(data []byte) error {
	var raw struct {
		ID          string            `json:"id"`
		Content     json.RawMessage   `json:"content,omitempty"`
		Parent      *uint32           `json:"parent,omitempty"`
		Children    []uint32          `json:"children,omitempty"`
		Annotations []TextAnnotation  `json:"annotations,omitempty"`
		Attributes  map[string]string `json:"attributes,omitempty"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	s.ID = raw.ID
	s.Parent = raw.Parent
	s.Children = raw.Children
	s.Annotations = raw.Annotations
	s.Attributes = raw.Attributes
	if len(raw.Content) > 0 && string(raw.Content) != "null" {
		v, err := UnmarshalNodeContent(raw.Content)
		if err != nil {
			return err
		}
		s.Content = v
	}
	return nil
}

// TextAnnotation styling or semantic annotation that applies to a byte range within a node's text.
//
// Unlike [`DocumentNode`], which captures block-level structure (headings, paragraphs, etc.),
// a `TextAnnotation` describes inline-level markup — bold, italic, links, code spans, and
// similar — that spans a contiguous run of bytes inside `DocumentNode::content`'s text field.
//
// Byte offsets (`start`..`end`) are into the UTF-8 encoded text of the parent node. The range
// is half-open: `start` is inclusive and `end` is exclusive.
//
// Multiple annotations on the same node can overlap (e.g. bold-italic text), and they are
// stored in the order they are encountered during DOM traversal.
//
// See [`AnnotationKind`] for the full list of supported annotation types.
type TextAnnotation struct {
	Start uint32         `json:"start"`
	End   uint32         `json:"end"`
	Kind  AnnotationKind `json:"kind"`
}

func (s *TextAnnotation) UnmarshalJSON(data []byte) error {
	var raw struct {
		Start uint32          `json:"start"`
		End   uint32          `json:"end"`
		Kind  json.RawMessage `json:"kind,omitempty"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	s.Start = raw.Start
	s.End = raw.End
	if len(raw.Kind) > 0 && string(raw.Kind) != "null" {
		v, err := UnmarshalAnnotationKind(raw.Kind)
		if err != nil {
			return err
		}
		s.Kind = v
	}
	return nil
}

// MetadataEntry single key-value metadata entry from `<head>` meta tags.
//
// Binding-safe replacement for `(String, String)` tuples used in
// [`NodeContent::MetadataBlock`]. Tuple pairs cannot be represented
// across language boundaries without lossy degradation.
type MetadataEntry struct {
	Key   string `json:"key"`
	Value string `json:"value"`
}

// ConversionResult primary result of HTML conversion and extraction.
//
// Contains the converted text output, optional structured document tree,
// metadata, extracted tables, images, and processing warnings.
//
// Example:
//
//	let result = convert("<h1>Hello</h1><p>World</p>", None)?;
//	assert!(result.content.is_some());
//	assert!(result.warnings.is_empty());
type ConversionResult struct {
	Content  *string             `json:"content,omitempty"`
	Document *DocumentStructure  `json:"document,omitempty"`
	Metadata HTMLMetadata        `json:"metadata"`
	Tables   []TableData         `json:"tables,omitempty"`
	Warnings []ProcessingWarning `json:"warnings,omitempty"`
}

// TableGrid structured table grid with cell-level data including spans.
type TableGrid struct {
	Rows  uint32     `json:"rows"`
	Cols  uint32     `json:"cols"`
	Cells []GridCell `json:"cells,omitempty"`
}

// GridCell single cell in a table grid.
type GridCell struct {
	Content  string `json:"content"`
	Row      uint32 `json:"row"`
	Col      uint32 `json:"col"`
	RowSpan  uint32 `json:"row_span"`
	ColSpan  uint32 `json:"col_span"`
	IsHeader bool   `json:"is_header"`
}

// TableData top-level extracted table with both structured data and markdown representation.
type TableData struct {
	Grid     TableGrid `json:"grid"`
	Markdown string    `json:"markdown"`
}

// ProcessingWarning non-fatal diagnostic produced during HTML conversion.
//
// Warnings indicate that conversion completed but some content may have been handled
// differently than expected — for example, an image that could not be extracted, a truncated
// input, or malformed HTML that was repaired with best-effort parsing.
//
// Conversion always succeeds (returns `ConversionResult`) even when warnings are
// present. Callers should inspect `warnings` and decide how to
// handle them based on their tolerance for partial results:
//
// - **Logging pipelines**: emit each warning at `WARN` level and continue.
// - **Strict pipelines**: treat any warning as a hard error by checking
// `result.warnings.is_empty()` before using the output.
//
// See [`WarningKind`] for the full taxonomy of warning categories.
type ProcessingWarning struct {
	Message string      `json:"message"`
	Kind    WarningKind `json:"kind"`
}

// VisitorHandle is an opaque handle type.
type VisitorHandle struct {
	ptr unsafe.Pointer
}

// Free releases the resources held by this handle.
func (h *VisitorHandle) Free() {
	if h.ptr != nil {
		C.htm_visitor_handle_free((*C.HTMVisitorHandle)(h.ptr))
		h.ptr = nil
	}
}

// Convert HTML to Markdown, Djot, or plain text.
//
// Returns a [`ConversionResult`] with converted content plus optional metadata,
// document structure, table data, inline images, and warnings depending on the
// enabled features and conversion options.
//
// Arguments:
//   - html: — the HTML string to convert.
//   - options: — conversion options. Rust accepts bare [`ConversionOptions`], `Some(options)`, or `None`. Language bindings expose the same option fields through native constructors or optional parameters.
//
// Errors are returned when returns an error if HTML parsing fails or if the input contains invalid UTF-8.
//
// Example:
//
//	let html = "<h1>Hello World</h1>";
//
//	// Bare options — most ergonomic.
//	let result = convert(html, ConversionOptions::default());
//	assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
//
//	// `None` falls back to defaults.
//	let result = convert(html, None);
//	assert!(result.content.as_deref().unwrap_or("").contains("Hello World"));
func Convert(html string, options *ConversionOptions) (*ConversionResult, error) {
	if options != nil && options.Visitor != nil {
		return convertWithVisitorHelper(html, options, options.Visitor)
	}
	chtml := C.CString(html)
	defer C.free(unsafe.Pointer(chtml))
	var cOptions *C.HTMConversionOptions
	if options != nil {
		jsonBytes, err := json.Marshal(options)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal options: %w", err)
		}
		tmpStr := C.CString(string(jsonBytes))
		cOptions = C.htm_conversion_options_from_json(tmpStr)
		if cOptions == nil {
			if err := lastError(); err != nil {
				C.free(unsafe.Pointer(tmpStr))
				return nil, err
			}
			C.free(unsafe.Pointer(tmpStr))
			return nil, fmt.Errorf("failed to decode conversion options")
		}
		C.free(unsafe.Pointer(tmpStr))
		defer C.htm_conversion_options_free(cOptions)
	}
	ptr := C.htm_convert(chtml, cOptions)
	if ptr == nil {
		if err := lastError(); err != nil {
			return nil, err
		}
		return nil, fmt.Errorf("conversion returned nil")
	}
	defer C.htm_conversion_result_free(ptr)

	jsonPtr := C.htm_conversion_result_to_json(ptr)
	if jsonPtr == nil {
		return nil, fmt.Errorf("failed to convert result to JSON")
	}
	defer C.htm_free_string(jsonPtr)
	var result ConversionResult
	if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
		return nil, fmt.Errorf("failed to unmarshal result: %w", err)
	}
	return &result, nil
}

// IsValid validate that the header level is within valid range (1-6).
//
// Returns `true` if level is 1-6, `false` otherwise.
//
// Example:
//
//	let valid = HeaderMetadata {
//	    level: 3,
//	    text: "Title".to_string(),
//	    id: None,
//	    depth: 2,
//	    html_offset: 100,
//	};
//	assert!(valid.is_valid());
//
//	let invalid = HeaderMetadata {
//	    level: 7,  // Invalid
//	    text: "Title".to_string(),
//	    id: None,
//	    depth: 2,
//	    html_offset: 100,
//	};
//	assert!(!invalid.is_valid());
func (r *HeaderMetadata) IsValid() (bool, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return false, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.htm_header_metadata_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return false, fmt.Errorf("failed to create receiver: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_header_metadata_free(cRecv)
	ptr := C.htm_header_metadata_is_valid(cRecv)
	return ptr != 0, nil
}

// Attributes return a reference to the attribute map.
//
// If the context was built with [`NodeContext::with_lazy_attributes`], the
// map is materialized on the first call and cached for subsequent calls.
// If this method is never called, no allocation occurs for attributes.
func (r *NodeContext) Attributes() (map[string]string, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.htm_node_context_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return nil, fmt.Errorf("failed to create receiver: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_node_context_free(cRecv)
	ptr := C.htm_node_context_attributes(cRecv)
	return func() map[string]string {
		if ptr == nil {
			return nil
		}
		defer C.htm_free_string(ptr)
		var result map[string]string
		if err := json.Unmarshal([]byte(C.GoString(ptr)), &result); err != nil {
			return nil
		}
		return result
	}(), nil
}

// WithOwnedAttributes construct a `NodeContext` with an owned attribute map.
//
// Use this when the caller already has materialized attributes.
func NodeContextWithOwnedAttributes(nodeType NodeType, tagName string, attributes map[string]string, depth uint, indexInParent uint, parentTag *string, isInline bool) (*NodeContext, error) {
	cNodeTypeStr := C.CString(string(nodeType))
	defer C.free(unsafe.Pointer(cNodeTypeStr))
	cNodeType := C.htm_node_type_from_str(cNodeTypeStr)

	cTagName := C.CString(tagName)
	defer C.free(unsafe.Pointer(cTagName))

	jsonBytescAttributes, err := json.Marshal(attributes)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal: %w", err)
	}
	cAttributes := C.CString(string(jsonBytescAttributes))
	defer C.free(unsafe.Pointer(cAttributes))

	cDepth := C.size_t(uint(depth))

	cIndexInParent := C.size_t(uint(indexInParent))

	var cParentTag *C.char
	if parentTag != nil {
		cParentTag = C.CString(*parentTag)
		defer C.free(unsafe.Pointer(cParentTag))
	}

	var cIsInline C.int32_t
	if isInline {
		cIsInline = 1
	} else {
		cIsInline = 0
	}

	ptr := C.htm_node_context_with_owned_attributes(cNodeType, cTagName, cAttributes, cDepth, cIndexInParent, cParentTag, cIsInline)
	defer C.htm_node_context_free(ptr)
	return func() *NodeContext {
		jsonPtr := C.htm_node_context_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.htm_free_string(jsonPtr)
		var result NodeContext
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}(), nil
}

// IntoOwned promote any borrowed fields into owned storage so the context can outlive `'a`.
func (r *NodeContext) IntoOwned() (*NodeContext, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.htm_node_context_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	if cRecv == nil {
		return nil, fmt.Errorf("failed to create receiver: %s", C.GoString(C.htm_last_error_context()))
	}
	defer C.htm_node_context_free(cRecv)
	ptr := C.htm_node_context_into_owned(cRecv)
	defer C.htm_node_context_free(ptr)
	return func() *NodeContext {
		jsonPtr := C.htm_node_context_to_json(ptr)
		if jsonPtr == nil {
			return nil
		}
		defer C.htm_free_string(jsonPtr)
		var result NodeContext
		if err := json.Unmarshal([]byte(C.GoString(jsonPtr)), &result); err != nil {
			return nil
		}
		return &result
	}(), nil
}
